1	import { describe, it, expect } from "vitest";
2	import { run } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list yields premium 5 G (only the processing fee)", () => {
7	    const result = run({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single main items at base premium (newcomer, first contract scenario adds first-insurance surcharge per-item; use plain config: years=0, with no prior contract) ---
15	  // We start with simpler cases: a long-standing customer (≥2 yrs) on a follow-up contract — but the simplest is one main item alone.
16	  // Use single-item, plain (no curse, no high enchantment) to test base premiums in isolation; modifiers will be tested in dedicated cases below.
17	
18	  it("single sword (plain) for newcomer → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
19	    const result = run({
20	      customer: { yearsWithMHPCO: 0 },
21	      steps: [
22	        {
23	          op: "quote",
24	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
25	        },
26	      ],
27	    });
28	    expect(result).toEqual({ results: [{ premium: 115 }] });
29	  });
30	  it("single amulet (plain) for newcomer → 60 + 6 + 5 = 71 G", () => {
31	    const result = run({
32	      customer: { yearsWithMHPCO: 0 },
33	      steps: [
34	        {
35	          op: "quote",
36	          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
37	        },
38	      ],
39	    });
40	    expect(result).toEqual({ results: [{ premium: 71 }] });
41	  });
42	  it("single staff (plain) for newcomer → 80 + 8 + 5 = 93 G", () => {
43	    const result = run({
44	      customer: { yearsWithMHPCO: 0 },
45	      steps: [
46	        {
47	          op: "quote",
48	          items: [{ type: "staff", material: "oak", enchantment: 2, cursed: false }],
49	        },
50	      ],
51	    });
52	    expect(result).toEqual({ results: [{ premium: 93 }] });
53	  });
54	  it.todo("single potion (plain) for newcomer → 40 + 4 + 5 = 49 G");
55	
56	  // --- Components: per-unit and block discount ---
57	  it.todo("2 runes → 50 G base premium (no block)");
58	  it.todo("3 runes → 60 G base premium (block of 3 alike)");
59	  it.todo("4 runes → 100 G base premium (no block — needs exactly 3)");
60	  it.todo("7 runes → 175 G base premium (no blocks applied to leftover groupings beyond 3-alike rule per spec example)");
61	
62	  // --- "Alike" components clarification ---
63	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
64	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
65	
66	  // --- Modifier scope on multi-item policy ---
67	  it.todo("cursed sword + plain amulet → policy base 160 G; curse adds 50 G (on sword base) → 210 G before policy modifiers and fee");
68	
69	  // --- Modifier thresholds ---
70	  it.todo("customer with exactly 2 years → loyalty discount applies");
71	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
72	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
73	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
74	
75	  // --- Insurance value sums & cap ---
76	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
77	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
78	  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only, not insurance sum");
79	  it.todo("two swords → insurance sum 2000 G, cap 4000 G");
80	
81	  // --- Claims: standard reimbursement (no special clauses) ---
82	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 − 100 deductible)");
83	  it.todo("rune (250 G), damage 200 → payout 100 (200 − 100 deductible; no enchantment/material on rune)");
84	
85	  // --- Claims: enchantment threshold ---
86	  it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (high-enchant 50% then deductible: 500 − 100)");
87	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses; 50% wins then deductible)");
88	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon: full then deductible)");
89	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (only high-enchant; 50% then deductible)");
90	
91	  // --- Deductible per damage event ---
92	  it.todo("dragon attack: sword damage 500 + amulet damage 300 → payout 600 (deductible per item: (500−100)+(300−100))");
93	
94	  // --- Multiple items of same type ---
95	  it.todo("two swords damaged → each treated as separate damage with its own deductible");
96	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");
97	
98	  // --- Cap exhaustion across successive claims ---
99	  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");
100	
101	  // --- Rounding ---
102	  it.todo("premium calculation that yields 197.5 → final 198 (rounded up)");
103	  it.todo("payout calculation that yields 350.5 → final 350 (rounded down)");
104	
105	  // --- Edge cases / errors ---
106	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with stderr message");
107	  it.todo("claim damages an item not in policy (e.g. amulet damaged when only sword insured) → CLI exits non-zero");
108	  it.todo("claim damages an item with unknown type → CLI exits non-zero");
109	  it.todo("claim with negative damage amount → CLI exits non-zero");
110	
111	  // --- Integration examples ---
112	  it.todo("newcomer with cursed steel sword (enchantment 3): 100 + 50 + 10 + 5 = 165 G");
113	  it.todo("3-year customer's second quote with cursed steel sword (enchantment 7): 100 + 50 + 30 − 20 + 10 − 15 + 5 = 160 G");
114	});
115	
116	describe("MHPCO CLI", () => {
117	  it.todo("CLI reads JSON scenario from stdin and writes results JSON to stdout");
118	});
