1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type QuoteStep = { op: "quote"; items: Item[] };
12	type Scenario = {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	};
16	type QuoteResult = { premium: number };
17	
18	const itemPremium = (item: Item): number => {
19	  const base = BASE_PREMIUMS[item.type];
20	  return base + base * FIRST_INSURANCE_SURCHARGE;
21	};
22	
23	const quotePremium = (step: QuoteStep): QuoteResult => {
24	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
25	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
26	};
27	
28	export const run = (scenario: Scenario): { results: QuoteResult[] } => {
29	  return { results: scenario.steps.map(quotePremium) };
30	};
